### Step 3: Update NextAuth Configuration

Modify `/auth.ts` to integrate rate limiting:

```typescript
import NextAuth from 'next-auth';
import Credentials from 'next-auth/providers/credentials';
import { prisma } from '@/lib/prisma';
import { verifyPassword } from '@/lib/password';
import { authConfig } from './auth.config';
import { checkRateLimit, recordLoginAttempt } from '@/lib/rate-limit';
import { getIpAddress } from '@/lib/ip-address';

/**
 * Full auth configuration with Credentials provider
 * This file runs in Node.js runtime (not Edge), so it can use Prisma
 */
export const { handlers, auth, signIn, signOut } = NextAuth({
  ...authConfig,
  providers: [
    Credentials({
      name: 'credentials',
      credentials: {
        email: { label: 'Email', type: 'email' },
        password: { label: 'Password', type: 'password' },
      },
      async authorize(credentials, request) {
        if (!credentials?.email || !credentials?.password) {
          return null;
        }

        const email = credentials.email as string;
        const password = credentials.password as string;

        // Extract IP address from request
        const ipAddress = getIpAddress(request as Request);

        // Check rate limit BEFORE database queries
        const rateLimit = await checkRateLimit(email, ipAddress);

        if (rateLimit.isLocked) {
          // Account is locked - throw descriptive error
          const lockedByText = rateLimit.lockedBy === 'email'
            ? 'Too many failed login attempts'
            : 'Too many failed login attempts from this location';

          throw new Error(
            `${lockedByText}. Please try again in ${rateLimit.remainingMinutes} minute${
              rateLimit.remainingMinutes !== 1 ? 's' : ''
            } or reset your password.`
          );
        }

        // Find user by email
        const user = await prisma.user.findUnique({
          where: { email: email.toLowerCase() },
        });

        if (!user) {
          // User not found - record failed attempt
          await recordLoginAttempt(email, ipAddress, false);
          return null;
        }

        // Verify password
        const isPasswordValid = await verifyPassword(password, user.password);

        // Record login attempt (success or failure)
        await recordLoginAttempt(email, ipAddress, isPasswordValid);

        if (!isPasswordValid) {
          return null;
        }

        // Return user object (will be encoded in session)
        return {
          id: user.id,
          name: user.name,
          email: user.email,
        };
      },
    }),
  ],
});
