import { NextRequest } from 'next/server';

/**
 * Extract IP address from request
 * Handles proxy headers (X-Forwarded-For, X-Real-IP)
 *
 * @param request - NextRequest or standard Request object
 * @returns IP address string
 */
export function getIpAddress(request: NextRequest | Request): string {
  // Priority 1: X-Forwarded-For (most common with proxies/load balancers)
  const forwardedFor = request.headers.get('x-forwarded-for');
  if (forwardedFor) {
    // X-Forwarded-For can be a comma-separated list: "client, proxy1, proxy2"
    // We want the first one (original client)
    return forwardedFor.split(',')[0].trim();
  }

  // Priority 2: X-Real-IP (nginx specific)
  const realIp = request.headers.get('x-real-ip');
  if (realIp) {
    return realIp.trim();
  }

  // Priority 3: CF-Connecting-IP (Cloudflare)
  const cfIp = request.headers.get('cf-connecting-ip');
  if (cfIp) {
    return cfIp.trim();
  }

  // Priority 4: Fallback to unknown
  return '0.0.0.0';
}

/**
 * Mask IP address for logging (privacy)
 * Example: 192.168.1.100 -> 192.168.x.x
