}

/**
 * Clean up old login attempts (maintenance function)
 * Can be called periodically to keep database size manageable
 */
export async function cleanupOldAttempts(): Promise<number> {
  const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);

  const result = await prisma.loginAttempt.deleteMany({
    where: {
      createdAt: {
        lt: oneDayAgo,
      },
    },
  });

  return result.count;
}
```

