### Unit Tests

Create `/lib/rate-limit.test.ts`:

```typescript
import { describe, it, expect, beforeEach } from 'vitest';
import { checkRateLimit, recordLoginAttempt } from './rate-limit';
import { prisma } from './prisma';

describe('Rate Limiting', () => {
  beforeEach(async () => {
    // Clean up test data
    await prisma.loginAttempt.deleteMany();
  });

  it('should allow login when no previous attempts', async () => {
    const result = await checkRateLimit('test@example.com', '192.168.1.1');

    expect(result.isLocked).toBe(false);
    expect(result.remainingMinutes).toBe(0);
  });

  it('should lock account after 5 failed attempts', async () => {
    const email = 'test@example.com';
    const ip = '192.168.1.1';

    // Record 5 failed attempts
    for (let i = 0; i < 5; i++) {
      await recordLoginAttempt(email, ip, false);
    }

    const result = await checkRateLimit(email, ip);

    expect(result.isLocked).toBe(true);
    expect(result.lockedBy).toBe('email');
    expect(result.remainingMinutes).toBeGreaterThan(0);
  });

  it('should lock IP after 10 failed attempts', async () => {
    const ip = '192.168.1.1';

    // Record 10 failed attempts from different emails
    for (let i = 0; i < 10; i++) {
      await recordLoginAttempt(`user${i}@example.com`, ip, false);
    }

    const result = await checkRateLimit('new@example.com', ip);

    expect(result.isLocked).toBe(true);
    expect(result.lockedBy).toBe('ip');
  });

  it('should reset counter after successful login', async () => {
    const email = 'test@example.com';
    const ip = '192.168.1.1';

    // Record 3 failed attempts
    await recordLoginAttempt(email, ip, false);
    await recordLoginAttempt(email, ip, false);
    await recordLoginAttempt(email, ip, false);

    // Record successful login
    await recordLoginAttempt(email, ip, true);

    // Should not be locked
    const result = await checkRateLimit(email, ip);
    expect(result.isLocked).toBe(false);
  });
});
```

